class Solution(object):
    def isUnivalTree(self, root):
        def dfs(node):
            if not node:
                return True
            if node.left and node.left.val != node.val:
                return False
            if node.right and node.right.val != node.val:
                return False
            return dfs(node.left) and dfs(node.right)
        return dfs(root)
